import axios from 'axios';
import {BASE_PATH_APIS} from '../../utils/constants';

class MasterDataService {

    async fetchMasterDataConf() {
        try {
            const response = await axios.get(BASE_PATH_APIS.basePathForAPIS+'/app/rest/carrier_allocation/get_config');
            return response;
        } catch (error) {

        }
        return null;
    }

    async getUserType() {
        try {
            const response = await axios.get(BASE_PATH_APIS.basePathForAPIS+'/app/rest/user_type');
            return response;
        } catch (error) {

            return [];
        }
    }

    async saveMasterDataConf(masterData) {
        try {
            const response = await axios.post(BASE_PATH_APIS.basePathForAPIS+'/app/rest/carrier_allocation/save_config', masterData);
            return response;
        } catch (error) {
            return error;
        }
    }

}

export const masterDataService = new MasterDataService();